const author='\n<section class="author">\n    <div class="container">\n        <div class="row">\n            <div class="col-lg-8 offset-lg-2 col-md-12 col-12">\n                <h1 class="author-title">Joy Xie</h1>\n                <div class="author-des">\n                    網頁前端工程師，心血來潮會製作一些網頁小工具或是小玩具，希望製作出能夠解決問題或有趣的事物。\n                </div>\n            </div>\n        </div>\n    </div>\n</section>\n',Author={template:author};export default Author;